import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedVideo {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  status: 'completed' | 'processing' | 'failed';
}

export enum VideoAspectRatio {
  LANDSCAPE = '16:9',
  PORTRAIT = '9:16'
}

export enum VideoResolution {
  P720 = '720p',
  P1080 = '1080p'
}

export interface VideoConfig {
  aspectRatio: VideoAspectRatio;
  resolution: VideoResolution;
}

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

import { GoogleGenAI } from "@google/genai";
import { VideoAspectRatio, VideoResolution } from "../types";

export const generateVideo = async (
  prompt: string, 
  aspectRatio: VideoAspectRatio = VideoAspectRatio.LANDSCAPE,
  resolution: VideoResolution = VideoResolution.P1080
): Promise<string> => {
  // Always create a new instance right before the call as per guidelines for Veo models
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: resolution,
        aspectRatio: aspectRatio
      }
    });

    // Poll until completion
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 8000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("No video URI returned from the API.");
    }

    // Append API key to fetch the actual video data
    const fetchUrl = `${downloadLink}&key=${process.env.API_KEY}`;
    const response = await fetch(fetchUrl);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error: any) {
    console.error("Video generation failed:", error);
    if (error.message?.includes("Requested entity was not found")) {
      throw new Error("API_KEY_EXPIRED");
    }
    throw error;
  }
};

import React, { useEffect, useState } from 'react';

interface ApiKeyManagerProps {
  onKeyValidated: () => void;
}

const ApiKeyManager: React.FC<ApiKeyManagerProps> = ({ onKeyValidated }) => {
  const [hasKey, setHasKey] = useState<boolean>(false);

  useEffect(() => {
    const checkKey = async () => {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (selected) {
        setHasKey(true);
        onKeyValidated();
      }
    };
    checkKey();
  }, [onKeyValidated]);

  const handleSelectKey = async () => {
    await window.aistudio.openSelectKey();
    // Guideline: Assume successful after triggering and proceed
    setHasKey(true);
    onKeyValidated();
  };

  if (hasKey) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md px-4">
      <div className="max-w-md w-full bg-zinc-900 border border-zinc-800 p-8 rounded-2xl shadow-2xl text-center">
        <div className="mb-6 inline-flex p-4 bg-indigo-500/10 rounded-full">
          <svg className="w-12 h-12 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
          </svg>
        </div>
        <h2 className="text-2xl font-bold text-white mb-2">Connect to Google Cloud</h2>
        <p className="text-zinc-400 mb-8 leading-relaxed">
          To generate high-quality videos with Gemini Veo, you need to select a billing-enabled API key from Google AI Studio.
        </p>
        <button
          onClick={handleSelectKey}
          className="w-full py-4 px-6 bg-indigo-600 hover:bg-indigo-500 text-white font-semibold rounded-xl transition-all shadow-lg shadow-indigo-500/20 active:scale-95 mb-4"
        >
          Select API Key
        </button>
        <a 
          href="https://ai.google.dev/gemini-api/docs/billing" 
          target="_blank" 
          rel="noopener noreferrer"
          className="text-indigo-400 hover:text-indigo-300 text-sm underline transition-colors"
        >
          Learn about billing and quotas
        </a>
      </div>
    </div>
  );
};

export default ApiKeyManager;

import React from 'react';
import { GeneratedVideo } from '../types';

interface VideoGridProps {
  videos: GeneratedVideo[];
  onPlay: (video: GeneratedVideo) => void;
}

const VideoGrid: React.FC<VideoGridProps> = ({ videos, onPlay }) => {
  if (videos.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 px-4 text-center border-2 border-dashed border-zinc-800 rounded-3xl">
        <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mb-4">
          <svg className="w-8 h-8 text-zinc-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
          </svg>
        </div>
        <h3 className="text-xl font-medium text-white mb-2">No videos yet</h3>
        <p className="text-zinc-500">Generate your first cinematic masterpiece above.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {videos.map((video) => (
        <div 
          key={video.id}
          className="group relative bg-zinc-900 border border-zinc-800 rounded-2xl overflow-hidden hover:border-indigo-500/50 transition-all cursor-pointer"
          onClick={() => onPlay(video)}
        >
          <div className="aspect-video bg-black flex items-center justify-center">
             <video 
              src={video.url} 
              className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity"
              muted
              onMouseOver={(e) => (e.target as HTMLVideoElement).play()}
              onMouseOut={(e) => {
                const v = e.target as HTMLVideoElement;
                v.pause();
                v.currentTime = 0;
              }}
            />
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none group-hover:scale-110 transition-transform">
              <div className="w-12 h-12 bg-white/10 backdrop-blur-md rounded-full flex items-center justify-center border border-white/20">
                <svg className="w-6 h-6 text-white ml-1" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M8 5v14l11-7z" />
                </svg>
              </div>
            </div>
          </div>
