    aspectRatio: VideoAspectRatio.LANDSCAPE,
    resolution: VideoResolution.P1080
  });

  const messageIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (isGenerating) {
      let i = 0;
      messageIntervalRef.current = window.setInterval(() => {
        i = (i + 1) % LOADING_MESSAGES.length;
        setLoadingMessage(LOADING_MESSAGES[i]);
      }, 3000);
    } else {
      if (messageIntervalRef.current) clearInterval(messageIntervalRef.current);
    }
    return () => {
      if (messageIntervalRef.current) clearInterval(messageIntervalRef.current);
    };
  }, [isGenerating]);

  const handleGenerate = async () => {
    if (!prompt.trim() || isGenerating) return;

    setIsGenerating(true);
    try {
      const videoUrl = await generateVideo(prompt, config.aspectRatio, config.resolution);
      const newVideo: GeneratedVideo = {
        id: Math.random().toString(36).substring(7),
        url: videoUrl,
        prompt: prompt,
        timestamp: Date.now(),
        status: 'completed'
      };
      setVideos(prev => [newVideo, ...prev]);
      setPrompt('');
    } catch (error: any) {
      if (error.message === "API_KEY_EXPIRED") {
        setIsKeyValid(false);
      } else {
        alert("Generation failed. Please check your prompt and try again.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePromptSuggestion = (text: string) => {
    setPrompt(text);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a]">
      <ApiKeyManager onKeyValidated={() => setIsKeyValid(true)} />

      {/* Header */}
      <header className="sticky top-0 z-40 bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-800">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-white">Gemini Video Studio</h1>
              <p className="text-xs text-zinc-500 font-semibold uppercase tracking-wider">Veo 3.1 Pro Engines</p>
            </div>
          </div>
          <div className="hidden md:flex items-center gap-4">
             <button 
              onClick={() => setIsKeyValid(false)}
              className="text-xs font-bold text-zinc-400 hover:text-white transition-colors flex items-center gap-2"
            >
              <div className="w-2 h-2 rounded-full bg-green-500"></div>
              API CONNECTED
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-12">
        {/* Generator Section */}
        <section className="mb-16">
          <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-6 md:p-8 shadow-2xl relative overflow-hidden">
            {/* Background Accent */}
            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-600/5 blur-[100px] rounded-full pointer-events-none"></div>

            <div className="relative z-10">
              <h2 className="text-3xl font-bold text-white mb-2">Create cinematic motion</h2>
              <p className="text-zinc-400 mb-8">Describe the scene you want to bring to life.</p>

              <div className="flex flex-col gap-6">
                <div className="relative">
                  <textarea
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="A neon-lit cyberpunk street in the rain with holographic signs reflecting on puddles, slow cinematic pan..."
                    className="w-full h-40 bg-zinc-950 border border-zinc-800 rounded-2xl p-6 text-white placeholder-zinc-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 transition-all resize-none text-lg"
                    disabled={isGenerating}
                  />

                  {isGenerating && (
                    <div className="absolute inset-0 bg-zinc-950/80 backdrop-blur-sm rounded-2xl flex flex-col items-center justify-center text-center p-6">
                      <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin mb-6"></div>
                      <p className="text-xl font-semibold text-white mb-2">{loadingMessage}</p>
                      <p className="text-zinc-500 text-sm">Video generation typically takes 1-2 minutes</p>
                    </div>
                  )}
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                  <div className="flex flex-wrap gap-4 w-full md:w-auto">
                    <div className="flex flex-col gap-1.5">
                      <label className="text-xs font-bold text-zinc-500 uppercase ml-1">Aspect Ratio</label>
                      <select 
                        className="bg-zinc-800 text-white text-sm px-4 py-2.5 rounded-xl border border-zinc-700 outline-none focus:ring-1 focus:ring-indigo-500"
                        value={config.aspectRatio}
                        onChange={(e) => setConfig({...config, aspectRatio: e.target.value as VideoAspectRatio})}
                      >
                        <option value={VideoAspectRatio.LANDSCAPE}>16:9 Landscape</option>
                        <option value={VideoAspectRatio.PORTRAIT}>9:16 Portrait</option>
                      </select>
                    </div>
                    <div className="flex flex-col gap-1.5">
                      <label className="text-xs font-bold text-zinc-500 uppercase ml-1">Resolution</label>
                      <select 
                        className="bg-zinc-800 text-white text-sm px-4 py-2.5 rounded-xl border border-zinc-700 outline-none focus:ring-1 focus:ring-indigo-500"
                        value={config.resolution}
                        onChange={(e) => setConfig({...config, resolution: e.target.value as VideoResolution})}
                      >
                        <option value={VideoResolution.P720}>720p HD</option>
                        <option value={VideoResolution.P1080}>1080p FHD</option>
                      </select>
                    </div>
                  </div>

                  <button
                    onClick={handleGenerate}
                    disabled={isGenerating || !prompt.trim()}
                    className={`group w-full md:w-auto flex items-center justify-center gap-3 px-10 py-4 rounded-xl font-bold transition-all shadow-xl ${
                      isGenerating || !prompt.trim() 
                        ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed' 
                        : 'bg-white text-black hover:bg-zinc-200 shadow-white/10 active:scale-95'
                    }`}
                  >
                    <svg className={`w-5 h-5 ${isGenerating ? 'animate-pulse' : 'group-hover:rotate-12 transition-transform'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                    {isGenerating ? 'GENERATING...' : 'GENERATE VIDEO'}
                  </button>
                </div>
              </div>

              <div className="mt-8 pt-8 border-t border-zinc-800">
                <p className="text-xs font-bold text-zinc-500 uppercase mb-4 ml-1">Prompt Inspirations</p>
                <div className="flex flex-wrap gap-2">
                  {[
                    "A space-age astronaut gardening on Mars",
                    "Close up of a dragon's eye with fire reflected",
                    "Cinematic drone shot over lush tropical islands",
                    "A neon cat riding a motorcycle in Tokyo"
                  ].map((suggest, i) => (
                    <button
                      key={i}
                      onClick={() => handlePromptSuggestion(suggest)}
                      className="px-4 py-2 bg-zinc-800/50 hover:bg-zinc-800 border border-zinc-700 rounded-full text-xs text-zinc-300 transition-colors"
                    >
                      {suggest}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Gallery Section */}
        <section>
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-2xl font-bold text-white">Your Production Gallery</h2>
            <p className="text-zinc-500 text-sm font-medium">{videos.length} clips generated</p>
          </div>
          <VideoGrid videos={videos} onPlay={(v) => setSelectedVideo(v)} />
        </section>
      </main>

      {/* Video Modal Player */}
      {selectedVideo && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 bg-black/95 backdrop-blur-sm">
          <div className="relative w-full max-w-6xl max-h-full flex flex-col items-center">
            <button 
              onClick={() => setSelectedVideo(null)}
              className="absolute -top-12 right-0 text-white hover:text-zinc-400 transition-colors p-2"
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>

            <div className="w-full bg-black rounded-3xl overflow-hidden shadow-2xl border border-zinc-800">
              <video 
                src={selectedVideo.url} 
                controls 
                autoPlay 
                className="w-full h-auto max-h-[70vh] object-contain"
              />
              <div className="p-6 md:p-8 bg-zinc-900">
                <h3 className="text-xl font-bold text-white mb-2">Original Prompt</h3>
                <p className="text-zinc-400 leading-relaxed">{selectedVideo.prompt}</p>

                <div className="mt-6 flex flex-wrap gap-4 pt-6 border-t border-zinc-800">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-zinc-500 font-bold uppercase tracking-wider">Engine</span>
                    <span className="text-sm font-semibold text-zinc-300">Veo 3.1 Fast</span>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] text-zinc-500 font-bold uppercase tracking-wider">Format</span>
                    <span className="text-sm font-semibold text-zinc-300">{selectedVideo.url.split('.').pop()?.toUpperCase() || 'MP4'}</span>
                  </div>
                  <a 
                    href={selectedVideo.url} 
                    download={`gemini-video-${selectedVideo.id}.mp4`}
                    className="ml-auto px-6 py-2 bg-white text-black font-bold rounded-lg text-sm hover:bg-zinc-200 transition-colors flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Download
                  </a>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="mt-24 border-t border-zinc-900 py-12 px-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-8 opacity-40 hover:opacity-100 transition-opacity">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-zinc-800 rounded flex items-center justify-center">
              <div className="w-2 h-2 bg-indigo-500 rounded-full"></div>
            </div>
            <span className="text-sm font-bold text-zinc-500 tracking-tight">GEMINI VIDEO STUDIO v1.0</span>
          </div>
          <div className="flex gap-8 text-xs font-bold text-zinc-500">
            <a href="#" className="hover:text-white">API DOCUMENTATION</a>
            <a href="#" className="hover:text-white">TERMS</a>
            <a href="#" className="hover:text-white">PRIVACY</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

