  onClose: () => void;
  onSave: (key: string) => void;
  initialError?: string | null;
}

const ApiKeyModal: React.FC<ApiKeyModalProps> = ({ isOpen, onClose, onSave, initialError }) => {
  const [key, setKey] = useState('');
  const [isVisible, setIsVisible] = useState(false);

