const App: React.FC = () => {
    // --- API KEY STATE ---
    // GUIDELINE: Users must select their own API key via window.aistudio for Veo generation.
    // Removed manual input form in favor of mandatory modal.
    const [isKeySelected, setIsKeySelected] = useState(false);

    // --- VIDEO CAPTURE STATE ---
    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [error, setError] = useState<string>('');
    const [frames, setFrames] = useState<Frame[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);

    // --- VEO GENERATION STATE ---
    const [genPrompt, setGenPrompt] = useState('');
    const [generatedVideos, setGeneratedVideos] = useState<GeneratedVideo[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);

    const videoRef = useRef<HTMLVideoElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleApiError = useCallback(async (err: any) => {
        const msg = err.message || "";
        // GUIDELINE: If the request fails with 401/403 or "Requested entity was not found", prompt the user to select a key again.
        if (msg.includes("API_KEY_INVALID") || msg.includes("Requested entity was not found") || msg.includes("401") || msg.includes("403")) {
            await window.aistudio.openSelectKey();
            setIsKeySelected(true);
        } else {
            setError(msg);
        }
    }, []);

    // --- VIDEO GENERATION ---
    const handleGenerateVideo = async () => {
        if (!genPrompt.trim() || isGenerating) return;
        setIsGenerating(true);
        setError('');
        try {
            // GUIDELINE: The generateVideo service uses process.env.API_KEY injected by aistudio
            const url = await generateVideo(genPrompt, VideoAspectRatio.LANDSCAPE, VideoResolution.P1080);
            const newVideo: GeneratedVideo = {
                id: Math.random().toString(36).substring(7),
                url,
                prompt: genPrompt,
                timestamp: Date.now(),
                status: 'completed'
            };
            setGeneratedVideos(prev => [newVideo, ...prev]);
            setGenPrompt('');
        } catch (err) {
            handleApiError(err);
        } finally {
            setIsGenerating(false);
        }
    };

    // --- IMAGE PROCESSING ---
    const handleImageProcessing = async (sourceId: string, prompt: string, title: string) => {
        const frame = frames.find(f => f.id === sourceId);
        if (!frame || isProcessing) return;

        setIsProcessing(true);
        setError('');
        try {
            // GUIDELINE: Create a new GoogleGenAI instance right before making an API call to use the latest key
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const base64 = frame.src.split(',')[1];
            const mimeType = frame.src.match(/data:(.*);/)?.[1] || 'image/png';

            // GUIDELINE: Use gemini-2.5-flash-image for general image editing tasks
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { 
                  parts: [
                    { inlineData: { data: base64, mimeType } }, 
                    { text: prompt }
                  ] 
                }
            });

            let processedBase64: string | undefined;
            // GUIDELINE: Iterate through response parts to find the generated image
            if (response.candidates?.[0]?.content?.parts) {
                for (const part of response.candidates[0].content.parts) {
                    if (part.inlineData) {
                        processedBase64 = part.inlineData.data;
                        break;
                    }
                }
            }

            if (processedBase64) {
                setFrames(prev => [...prev, {
                    id: crypto.randomUUID(),
                    src: `data:image/png;base64,${processedBase64}`,
                    title,
                    prompt: '',
                    originalFileName: `edited-${frame.originalFileName}`
                }]);
            } else {
                throw new Error("No image data returned from model.");
            }
        } catch (err: any) {
            handleApiError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    // --- VIDEO HANDLERS ---
    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file?.type === 'video/mp4') {
            setVideoSrc(URL.createObjectURL(file));
        }
    };

    return (
        <div className="bg-zinc-950 min-h-screen text-white font-sans selection:bg-indigo-500/30">
            {/* GUIDELINE: Mandatory API Key Selection for Veo models */}
            <ApiKeyManager onKeyValidated={() => setIsKeySelected(true)} />

            {/* Header */}
            <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-800/50">
                <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                        </div>
                        <h1 className="text-xl font-bold tracking-tight">Gemini Studio</h1>
                    </div>

                    <button 
                        onClick={() => window.aistudio.openSelectKey()}
                        className="group flex items-center gap-2 px-4 py-2 rounded-full border border-zinc-800 bg-zinc-900 transition-all hover:border-zinc-700"
                    >
                        <div className="w-2 h-2 rounded-full bg-green-500" />
                        <span className="text-xs font-bold text-zinc-400 group-hover:text-white uppercase tracking-widest">
                            API Settings
                        </span>
                    </button>
                </div>
            </header>

            <main className="max-w-6xl mx-auto px-6 py-12">
                {error && (
                    <div className="mb-8 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm">
                        {error}
                    </div>
                )}

                {/* Generation Card */}
                <section className="mb-16">
                    <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-8 shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/5 blur-[120px] rounded-full pointer-events-none transition-opacity opacity-0 group-hover:opacity-100" />

                        <h2 className="text-2xl font-bold mb-2">Generate cinematic motion</h2>
                        <p className="text-zinc-500 text-sm mb-6">Create stunning clips using Veo 3.1 Fast</p>

                        <div className="flex flex-col gap-4">
                            <textarea
                                value={genPrompt}
                                onChange={(e) => setGenPrompt(e.target.value)}
                                placeholder="A close up of a majestic white tiger running through snow..."
                                className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white placeholder-zinc-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 resize-none"
                            />
                            <div className="flex justify-end">
                                <button
                                    onClick={handleGenerateVideo}
                                    disabled={isGenerating || !genPrompt.trim()}
                                    className="px-8 py-3 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {isGenerating ? <><SpinnerIcon /> Generating...</> : 'Generate Clip'}
                                </button>
                            </div>
                        </div>
                    </div>
                </section>

                {/* Player & Capture */}
                <section className="grid lg:grid-cols-2 gap-12 mb-16">
                    <div className="space-y-6">
                        <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-4 overflow-hidden">
                            {videoSrc ? (
                                <div className="space-y-4">
                                    <video 
                                        ref={videoRef} src={videoSrc} className="w-full rounded-2xl aspect-video bg-black"
                                        onLoadedMetadata={() => setDuration(videoRef.current?.duration || 0)}
                                        onTimeUpdate={() => setCurrentTime(videoRef.current?.currentTime || 0)}
                                    />
                                    <div className="flex items-center gap-4 px-2">
                                        <button onClick={() => {
                                            if (videoRef.current?.paused) videoRef.current.play();
                                            else videoRef.current?.pause();
                                            setIsPlaying(!videoRef.current?.paused);
                                        }} className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center hover:bg-zinc-700 transition-colors">
                                            {isPlaying ? <PauseIcon /> : <PlayIcon />}
                                        </button>
                                        <div className="flex-1 h-1.5 bg-zinc-800 rounded-full relative">
                                            <div 
                                                className="absolute inset-y-0 left-0 bg-indigo-500 rounded-full" 
                                                style={{ width: `${(currentTime/duration)*100}%` }}
                                            />
                                        </div>
                                        <span className="text-xs font-mono text-zinc-500">{formatTime(currentTime)} / {formatTime(duration)}</span>
                                    </div>
                                    <div className="flex gap-2">
                                        <button 
                                            onClick={() => {
                                                if (videoRef.current) {
                                                    const canvas = document.createElement('canvas');
                                                    canvas.width = videoRef.current.videoWidth;
                                                    canvas.height = videoRef.current.videoHeight;
                                                    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
                                                    setFrames(prev => [{
                                                        id: crypto.randomUUID(),
                                                        src: canvas.toDataURL('image/png'),
                                                        title: 'Captured Frame',
                                                        prompt: '',
                                                        originalFileName: `frame-${Date.now()}.png`
                                                    }, ...prev]);
                                                }
                                            }}
                                            className="flex-1 py-3 bg-zinc-800 hover:bg-zinc-700 rounded-xl text-sm font-bold transition-colors"
                                        >
                                            Capture Frame
                                        </button>
                                        <button 
                                            onClick={() => fileInputRef.current?.click()}
                                            className="flex-1 py-3 bg-zinc-900 border border-zinc-800 hover:border-zinc-700 rounded-xl text-sm font-bold transition-colors"
                                        >
                                            Change Video
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <div 
                                    onClick={() => fileInputRef.current?.click()}
                                    className="aspect-video flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-2xl hover:border-indigo-500/50 hover:bg-indigo-500/5 cursor-pointer transition-all"
                                >
                                    <UploadIcon />
                                    <p className="font-bold text-zinc-400">Select .mp4 to analyze</p>
                                </div>
                            )}
                            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="video/mp4" className="hidden" />
                        </div>
                    </div>

                    <div className="space-y-6">
                        <h3 className="text-xl font-bold flex items-center gap-2">
                            Captured Frames
                            <span className="text-xs text-zinc-600 bg-zinc-900 px-2 py-0.5 rounded-full">{frames.length}</span>
                        </h3>
                        <div className="grid sm:grid-cols-2 gap-4 max-h-[600px] overflow-y-auto pr-2 scrollbar-thin">
                            {frames.map(f => (
                                <div key={f.id} className="bg-zinc-900 border border-zinc-800 rounded-2xl p-3 space-y-3 group">
                                    <img src={f.src} className="w-full aspect-video object-cover rounded-xl" alt="captured" />
                                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button 
                                            onClick={() => handleImageProcessing(f.id, "remove all text and logos", "Clean Frame")}
                                            className="flex-1 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-[10px] font-bold rounded-lg transition-colors"
                                        >
                                            CLEAN
                                        </button>
                                        <button 
                                            onClick={() => {
                                                const a = document.createElement('a');
                                                a.href = f.src;
                                                a.download = f.originalFileName;
                                                a.click();
                                            }}
                                            className="flex-1 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-[10px] font-bold rounded-lg transition-colors"
                                        >
                                            SAVE
                                        </button>
                                        <button 
                                            onClick={() => setFrames(prev => prev.filter(x => x.id !== f.id))}
                                            className="px-2 py-1.5 bg-red-500/10 hover:bg-red-500/20 text-red-500 text-[10px] font-bold rounded-lg transition-colors"
                                        >
                                            X
                                        </button>
                                    </div>
                                </div>
                            ))}
                            {frames.length === 0 && (
                                <div className="col-span-full h-40 border border-dashed border-zinc-900 rounded-3xl flex items-center justify-center text-zinc-700 font-medium italic">
                                    Capture frames from the player to edit them
                                </div>
                            )}
                        </div>
                    </div>
                </section>

                {/* Video Grid */}
                <section>
                    <h2 className="text-2xl font-bold mb-8">Recent Generations</h2>
                    <VideoGrid videos={generatedVideos} onPlay={() => {}} />
                </section>
            </main>
        </div>
    );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { VideoAspectRatio, VideoResolution } from "../types";

export const generateVideo = async (
  prompt: string, 
  aspectRatio: VideoAspectRatio = VideoAspectRatio.LANDSCAPE,
  resolution: VideoResolution = VideoResolution.P1080
): Promise<string> => {
  // GUIDELINE: The API key must be obtained exclusively from the environment variable process.env.API_KEY.
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API_KEY_MISSING");
  }

  // GUIDELINE: Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
  const ai = new GoogleGenAI({ apiKey });

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: resolution,
        aspectRatio: aspectRatio
      }
    });

    // Poll until completion
    while (!operation.done) {
      // Poll every 10 seconds as recommended for long-running video generation operations
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("No video URI returned from the API.");
    }

    // GUIDELINE: The response.body contains the MP4 bytes. You must append an API key when fetching from the download link.
    const fetchUrl = `${downloadLink}&key=${apiKey}`;
    const response = await fetch(fetchUrl);

    if (!response.ok) {
        if (response.status === 401 || response.status === 403) throw new Error("API_KEY_INVALID");
        if (response.status === 429) throw new Error("API_QUOTA_EXCEEDED");
        throw new Error(`Fetch failed: ${response.statusText}`);
    }

    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error: any) {
    console.error("Video generation failed:", error);

    // Check for specific error patterns in the message or structure
    const msg = error.message?.toLowerCase() || "";
    // GUIDELINE: If the request fails with "Requested entity was not found.", reset the key selection state and prompt for a new key.
    if (msg.includes("unauthorized") || msg.includes("api key not valid") || msg.includes("requested entity was not found")) {
      throw new Error("API_KEY_INVALID");
    }
    if (msg.includes("quota") || msg.includes("429")) {
      throw new Error("API_QUOTA_EXCEEDED");
    }

    throw error;
  }
};

import { GoogleGenAI } from "@google/genai";
import { VideoAspectRatio, VideoResolution } from "../types";

export const generateVideo = async (
  prompt: string, 
  aspectRatio: VideoAspectRatio = VideoAspectRatio.LANDSCAPE,
  resolution: VideoResolution = VideoResolution.P1080,
  apiKey?: string
): Promise<string> => {
  // Prioritize passed key, then env variable
  const activeKey = apiKey || process.env.API_KEY;

  if (!activeKey) {
    throw new Error("API_KEY_MISSING");
  }

  const ai = new GoogleGenAI({ apiKey: activeKey });

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: resolution,
        aspectRatio: aspectRatio
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("No video URI returned from the API.");
    }

    const fetchUrl = `${downloadLink}&key=${activeKey}`;
    const response = await fetch(fetchUrl);

    if (!response.ok) {
        if (response.status === 401 || response.status === 403) throw new Error("API_KEY_INVALID");
        if (response.status === 429) throw new Error("API_QUOTA_EXCEEDED");
        throw new Error(`Fetch failed: ${response.statusText}`);
    }

    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error: any) {
    console.error("Video generation failed:", error);
    const msg = error.message?.toLowerCase() || "";
    if (msg.includes("unauthorized") || msg.includes("api key not valid") || msg.includes("401") || msg.includes("403")) {
      throw new Error("API_KEY_INVALID");
    }
    if (msg.includes("quota") || msg.includes("429")) {
      throw new Error("API_QUOTA_EXCEEDED");
    }
    throw error;
  }
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { VideoAspectRatio, VideoResolution, GeneratedVideo } from './types';
import { generateVideo } from './services/geminiService';
import ApiKeyModal from './components/ApiKeyModal';
import VideoGrid from './components/VideoGrid';

// --- FRAME INTERFACE ---
interface Frame {
    id: string;
    src: string;
    title: string;
    prompt: string;
    originalFileName: string;
}

// --- ICONS ---
const UploadIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-zinc-600 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 10.5l4.72-4.72a.75.75 0 011.28.53v11.38a.75.75 0 01-1.28.53l-4.72-4.72M4.5 18.75h9a2.25 2.25 0 002.25-2.25v-9A2.25 2.25 0 0013.5 5.25h-9A2.25 2.25 0 002.25 7.5v9A2.25 2.25 0 004.5 18.75z" />
    </svg>
);
const PlayIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M5 3l14 9-14 9V3z" /></svg>;
const PauseIcon = () => <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M6 4h4v16H6zM14 4h4v16h-4z" /></svg>;
const SpinnerIcon = () => <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>;

const formatTime = (s: number) => {
    const min = Math.floor(s / 60);
    const sec = Math.floor(s % 60);
    return `${String(min).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
};

const App: React.FC = () => {
    // --- API KEY STATE ---
    const [apiKey, setApiKey] = useState<string>(localStorage.getItem('GEMINI_CUSTOM_API_KEY') || '');
    const [isApiModalOpen, setIsApiModalOpen] = useState(false);
    const [apiError, setApiError] = useState<string | null>(null);

    // --- APP STATE ---
    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [error, setError] = useState<string>('');
    const [frames, setFrames] = useState<Frame[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);

    const [genPrompt, setGenPrompt] = useState('');
    const [generatedVideos, setGeneratedVideos] = useState<GeneratedVideo[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);

    const videoRef = useRef<HTMLVideoElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const getActiveKey = () => apiKey || process.env.API_KEY || '';

    // Error Handling Logic
    const handleApiError = useCallback((err: any) => {
        const msg = err.message || "";
        if (msg.includes("API_KEY_INVALID") || msg.includes("401") || msg.includes("403")) {
            setApiError("Invalid API Key. Please check your AI Studio settings and enter a valid key.");
            setIsApiModalOpen(true);
        } else if (msg.includes("API_QUOTA_EXCEEDED") || msg.includes("429")) {
            setApiError("Quota Exceeded. You have reached your Gemini API limit. Please wait or use a different key.");
            setIsApiModalOpen(true);
        } else if (msg.includes("API_KEY_MISSING")) {
            setApiError("An API Key is required to use this application.");
            setIsApiModalOpen(true);
        } else {
            setError(msg || "An unexpected error occurred. Please try again.");
        }
    }, []);

    const saveApiKey = (newKey: string) => {
        localStorage.setItem('GEMINI_CUSTOM_API_KEY', newKey);
        setApiKey(newKey);
        setApiError(null);
        setError(''); // Clear previous errors
    };

    // --- API ACTIONS ---
    const handleGenerateVideo = async () => {
        if (!genPrompt.trim() || isGenerating) return;

        const key = getActiveKey();
        if (!key) {
            setApiError("Please set your Gemini API Key before generating videos.");
            setIsApiModalOpen(true);
            return;
        }

        setIsGenerating(true);
        setError('');
        try {
            const url = await generateVideo(genPrompt, VideoAspectRatio.LANDSCAPE, VideoResolution.P1080, key);
            const newVideo: GeneratedVideo = {
                id: Math.random().toString(36).substring(7),
                url,
                prompt: genPrompt,
                timestamp: Date.now(),
                status: 'completed'
            };
            setGeneratedVideos(prev => [newVideo, ...prev]);
            setGenPrompt('');
        } catch (err) {
            handleApiError(err);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleImageProcessing = async (sourceId: string, prompt: string, title: string) => {
        const frame = frames.find(f => f.id === sourceId);
        if (!frame || isProcessing) return;

        const key = getActiveKey();
        if (!key) {
            setApiError("Please set your Gemini API Key before analyzing frames.");
            setIsApiModalOpen(true);
            return;
        }

        setIsProcessing(true);
        setError('');
        try {
            const ai = new GoogleGenAI({ apiKey: key });
            const base64 = frame.src.split(',')[1];
            const mimeType = frame.src.match(/data:(.*);/)?.[1] || 'image/png';

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { 
                  parts: [
                    { inlineData: { data: base64, mimeType } }, 
                    { text: prompt }
                  ] 
                }
            });

            let processedBase64: string | undefined;
            if (response.candidates?.[0]?.content?.parts) {
                for (const part of response.candidates[0].content.parts) {
                    if (part.inlineData) {
                        processedBase64 = part.inlineData.data;
                        break;
                    }
                }
            }

            if (processedBase64) {
                setFrames(prev => [{
                    id: crypto.randomUUID(),
                    src: `data:image/png;base64,${processedBase64}`,
                    title,
                    prompt: '',
                    originalFileName: `edited-${frame.originalFileName}`
                }, ...prev]);
            } else {
                throw new Error("API returned no image data.");
            }
        } catch (err: any) {
            handleApiError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
