const SpinnerIcon = () => <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>;

const formatTime = (s: number) => {
    const min = Math.floor(s / 60);
    const sec = Math.floor(s % 60);
    return `${String(min).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
};

const App: React.FC = () => {
    // --- APP STATE ---
    const [isApiValidated, setIsApiValidated] = useState(false);
    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [error, setError] = useState<string>('');
    const [frames, setFrames] = useState<Frame[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);

    const [genPrompt, setGenPrompt] = useState('');
    const [generatedVideos, setGeneratedVideos] = useState<GeneratedVideo[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);

    const videoRef = useRef<HTMLVideoElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Error Handling Logic
    const handleApiError = useCallback((err: any) => {
        const msg = err.message || "";
        // Guideline: If the request fails with "Requested entity was not found.", reset key selection state
        if (msg.includes("Requested entity was not found")) {
            setIsApiValidated(false);
            window.aistudio.openSelectKey().then(() => setIsApiValidated(true));
            return;
        }

        if (msg.includes("401") || msg.includes("403")) {
            setError("Authentication failed. Please re-select your API key via Settings.");
            setIsApiValidated(false);
        } else if (msg.includes("429")) {
            setError("Quota Exceeded. Please check your Gemini API billing/limits.");
        } else {
            setError(msg || "An unexpected error occurred. Please try again.");
        }
    }, []);

    // --- API ACTIONS ---
    const handleGenerateVideo = async () => {
        if (!genPrompt.trim() || isGenerating) return;

        setIsGenerating(true);
        setError('');
        try {
            // Generate video using Veo models (handled via generateVideo service)
            const url = await generateVideo(genPrompt, VideoAspectRatio.LANDSCAPE, VideoResolution.P1080);
            const newVideo: GeneratedVideo = {
                id: Math.random().toString(36).substring(7),
                url,
                prompt: genPrompt,
                timestamp: Date.now(),
                status: 'completed'
            };
            setGeneratedVideos(prev => [newVideo, ...prev]);
            setGenPrompt('');
        } catch (err) {
            handleApiError(err);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleImageProcessing = async (sourceId: string, prompt: string, title: string) => {
        const frame = frames.find(f => f.id === sourceId);
        if (!frame || isProcessing) return;

        setIsProcessing(true);
        setError('');
        try {
            // Guideline: Create a new GoogleGenAI instance right before making an API call
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const base64 = frame.src.split(',')[1];
            const mimeType = frame.src.match(/data:(.*);/)?.[1] || 'image/png';

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents: { 
                  parts: [
                    { inlineData: { data: base64, mimeType } }, 
                    { text: prompt }
                  ] 
                }
            });

            // Guideline: Iterate through response parts to find the image part for nano banana series models
            let processedBase64: string | undefined;
            if (response.candidates?.[0]?.content?.parts) {
                for (const part of response.candidates[0].content.parts) {
                    if (part.inlineData) {
                        processedBase64 = part.inlineData.data;
                        break;
                    }
                }
            }

            if (processedBase64) {
                setFrames(prev => [{
                    id: crypto.randomUUID(),
                    src: `data:image/png;base64,${processedBase64}`,
                    title,
                    prompt: '',
                    originalFileName: `edited-${frame.originalFileName}`
                }, ...prev]);
            } else {
                throw new Error("API returned no image data.");
            }
        } catch (err: any) {
            handleApiError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file?.type === 'video/mp4') {
            setVideoSrc(URL.createObjectURL(file));
            setFrames([]);
            setError('');
        } else if (file) {
            setError('Please select a valid .mp4 file.');
        }
    };

    return (
        <div className="bg-zinc-950 min-h-screen text-white font-sans selection:bg-indigo-500/30">
            {/* API Key management via window.aistudio integration */}
            {!isApiValidated && <ApiKeyManager onKeyValidated={() => setIsApiValidated(true)} />}

            {/* Sticky Header */}
            <header className="sticky top-0 z-40 bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-800/50">
                <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                        </div>
                        <h1 className="text-xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-zinc-400">
                            Video Frame Capture
                        </h1>
                    </div>

                    <button 
                        onClick={() => window.aistudio.openSelectKey().then(() => setIsApiValidated(true))}
                        className={`group flex items-center gap-2 px-4 py-2 rounded-full border transition-all duration-300 ${
                            isApiValidated ? 'bg-zinc-900 border-zinc-800 hover:border-zinc-700' : 'bg-indigo-500/10 border-indigo-500/30 animate-pulse'
                        }`}
                    >
                        <div className={`w-2 h-2 rounded-full ${isApiValidated ? 'bg-green-500' : 'bg-amber-500'}`} />
                        <span className="text-xs font-bold text-zinc-400 group-hover:text-white uppercase tracking-widest">
                            API Settings
                        </span>
                    </button>
                </div>
            </header>

            <main className="max-w-6xl mx-auto px-6 py-12 space-y-16">
                {error && (
