import ApiKeyManager from './components/ApiKeyManager';
import VideoGrid from './components/VideoGrid';

// --- FRAME INTERFACE ---
interface Frame {
    id: string;
    src: string;
    title: string;
    prompt: string;
    originalFileName: string;
}

