const SpinnerIcon = () => <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>;

const formatTime = (s: number) => {
    const min = Math.floor(s / 60);
    const sec = Math.floor(s % 60);
    return `${String(min).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
};

const App: React.FC = () => {
    // --- API KEY NOTEPAD STATES ---
    const [notepadKey, setNotepadKey] = useState<string>('');
    const [activeApiKey, setActiveApiKey] = useState<string>('');

    // --- APP STATE ---
    const [isApiValidated, setIsApiValidated] = useState(false);
    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [error, setError] = useState<string>('');
    const [frames, setFrames] = useState<Frame[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);

    const [genPrompt, setGenPrompt] = useState('');
    const [generatedVideos, setGeneratedVideos] = useState<GeneratedVideo[]>([]);
    const [isGenerating, setIsGenerating] = useState(false);

    // Model Selection State for Image Generation
    const [selectedImageModel, setSelectedImageModel] = useState<'gemini-2.5-flash-image' | 'gemini-3-pro-image-preview'>('gemini-2.5-flash-image');

    const videoRef = useRef<HTMLVideoElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // --- INITIALIZATION ---
    useEffect(() => {
        const savedKey = localStorage.getItem('GEMINI_CUSTOM_API_KEY');
        const envKey = process.env.API_KEY;
        const initialKey = savedKey || envKey || '';

        setActiveApiKey(initialKey);
        setNotepadKey(initialKey || 'no API key');
        if (initialKey) setIsApiValidated(true);
    }, []);

    // --- NOTEPAD HANDLERS ---
    const handleSendKey = () => {
        const cleanKey = notepadKey.trim();
        if (cleanKey && cleanKey !== 'no API key') {
            localStorage.setItem('GEMINI_CUSTOM_API_KEY', cleanKey);
            setActiveApiKey(cleanKey);
            setIsApiValidated(true);
            setError('');
        } else {
            setError('Please enter a valid API Key');
        }
    };

    const handleCopyKey = () => {
        navigator.clipboard.writeText(notepadKey).then(() => {
            // Success
        });
    };

    const handleClearKey = () => {
        setNotepadKey('');
    };

    // Error Handling Logic
    const handleApiError = useCallback((err: any) => {
        const msg = err.message || "";
        if (msg.includes("Requested entity was not found")) {
            setIsApiValidated(false);
            window.aistudio.openSelectKey().then(() => setIsApiValidated(true));
            return;
        }

        if (msg.includes("401") || msg.includes("403")) {
            setError("Authentication failed. Please check your API key.");
            setIsApiValidated(false);
        } else if (msg.includes("429")) {
            setError("Quota Exceeded. Please check your Gemini API billing/limits.");
        } else {
            setError(msg || "An unexpected error occurred. Please try again.");
        }
    }, []);

    // --- API ACTIONS ---
    const handleGenerateVideo = async () => {
        if (!genPrompt.trim() || isGenerating) return;

        setIsGenerating(true);
        setError('');
        try {
            // Use activeApiKey if available, fallback to process.env
            const url = await generateVideo(genPrompt, VideoAspectRatio.LANDSCAPE, VideoResolution.P1080);
            const newVideo: GeneratedVideo = {
                id: Math.random().toString(36).substring(7),
                url,
                prompt: genPrompt,
                timestamp: Date.now(),
                status: 'completed'
            };
            setGeneratedVideos(prev => [newVideo, ...prev]);
            setGenPrompt('');
        } catch (err) {
            handleApiError(err);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleImageProcessing = async (sourceId: string, prompt: string, title: string) => {
        const frame = frames.find(f => f.id === sourceId);
        if (!frame || isProcessing) return;

        const key = activeApiKey || process.env.API_KEY;
        if (!key) {
            setError('API Key is missing. Please enter one in the Notepad bar above.');
            return;
        }

        setIsProcessing(true);
        setError('');
        try {
            const ai = new GoogleGenAI({ apiKey: key });
            const base64 = frame.src.split(',')[1];
            const mimeType = frame.src.match(/data:(.*);/)?.[1] || 'image/png';

            const response = await ai.models.generateContent({
                model: selectedImageModel,
                contents: { 
                  parts: [
                    { inlineData: { data: base64, mimeType } }, 
                    { text: prompt }
                  ] 
                }
            });

            let processedBase64: string | undefined;
            if (response.candidates?.[0]?.content?.parts) {
                for (const part of response.candidates[0].content.parts) {
                    if (part.inlineData) {
                        processedBase64 = part.inlineData.data;
                        break;
                    }
                }
            }

            if (processedBase64) {
                setFrames(prev => [{
                    id: crypto.randomUUID(),
                    src: `data:image/png;base64,${processedBase64}`,
                    title,
                    prompt: '',
                    originalFileName: `edited-${frame.originalFileName}`
                }, ...prev]);
            } else {
                throw new Error("API returned no image data.");
            }
        } catch (err: any) {
            handleApiError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file?.type === 'video/mp4') {
            setVideoSrc(URL.createObjectURL(file));
            setFrames([]);
            setError('');
        } else if (file) {
            setError('Please select a valid .mp4 file.');
        }
    };

    return (
        <div className="bg-zinc-950 min-h-screen text-white font-sans selection:bg-indigo-500/30">
            {/* API KEY NOTEPAD BAR */}
            <div className="w-full bg-zinc-950 border-b border-zinc-800 p-3 shadow-lg sticky top-0 z-[60]">
                <div className="max-w-6xl mx-auto flex flex-col gap-2">
                    <div className="flex items-center justify-between px-1">
                        <label className="text-xs font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                            <span className={`w-2 h-2 rounded-full ${activeApiKey ? 'bg-green-500' : 'bg-red-500'} animate-pulse`}></span>
                            API key :
                        </label>
                        <div className="flex items-center gap-2">
                            <button 
                                onClick={handleSendKey}
                                className="px-4 py-1 bg-green-600/10 hover:bg-green-600/20 text-green-500 text-[10px] font-black rounded border border-green-500/20 transition-all uppercase tracking-tighter"
                            >
                                Send
                            </button>
                            <button 
                                onClick={handleCopyKey}
                                className="px-4 py-1 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 text-[10px] font-bold rounded border border-zinc-700 transition-all uppercase tracking-tighter"
                            >
                                Copy
                            </button>
                            <button 
                                onClick={handleClearKey}
                                className="px-4 py-1 bg-red-600/10 hover:bg-red-600/20 text-red-500 text-[10px] font-bold rounded border border-red-500/20 transition-all uppercase tracking-tighter"
                            >
                                Clear
                            </button>
                        </div>
                    </div>
                    <textarea 
                        value={notepadKey}
                        onChange={(e) => setNotepadKey(e.target.value)}
                        className="w-full h-12 bg-black border border-zinc-800 rounded p-2 text-green-400 font-mono text-xs resize-none focus:outline-none focus:border-green-500/30 whitespace-pre overflow-x-auto scrollbar-thin scrollbar-thumb-zinc-800"
                        placeholder="Enter Gemini API key..."
                    />
                </div>
            </div>

            {/* API Key management via window.aistudio integration */}
            {!isApiValidated && !activeApiKey && <ApiKeyManager onKeyValidated={() => setIsApiValidated(true)} />}

            {/* Sub-Header */}
            <header className="sticky top-[108px] z-40 bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-800/50">
                <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
                            <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                        </div>
                        <h1 className="text-lg font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-zinc-400">
                            Video Frame Capture
                        </h1>
                    </div>
                </div>
            </header>

            <main className="max-w-6xl mx-auto px-6 py-12 space-y-16">
                {error && (
                    <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
                        <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                        {error}
                    </div>
                )}

                {/* 1. Generation Section */}
                <section>
                    <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-8 shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-indigo-600/5 blur-[120px] rounded-full pointer-events-none transition-opacity opacity-0 group-hover:opacity-100" />

                        <div className="relative">
                            <h2 className="text-2xl font-bold mb-2">AI Video Generation</h2>
                            <p className="text-zinc-500 text-sm mb-6">Describe a scene to generate cinematic motion using Veo 3.1</p>

                            <div className="flex flex-col gap-4">
                                <textarea
                                    value={genPrompt}
                                    onChange={(e) => setGenPrompt(e.target.value)}
                                    placeholder="A high-speed drone shot through a neon-lit cyberpunk city..."
                                    className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white placeholder-zinc-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 resize-none transition-all"
                                />
                                <div className="flex justify-end">
                                    <button
