    return (
        <div className="bg-zinc-950 min-h-screen text-white font-sans selection:bg-indigo-500/30">

            {/* API KEY NOTEPAD BAR (Full width, 2 lines, editable) */}
            <div className="w-full bg-zinc-950 border-b border-zinc-800 p-2 shadow-xl sticky top-0 z-[100]">
                <div className="max-w-screen-2xl mx-auto flex flex-col gap-2">
