                        <div className="flex items-center gap-2">
                            <button onClick={handleSendKey} className="px-3 py-1 bg-green-600/10 hover:bg-green-600/20 text-green-500 text-[10px] font-bold rounded border border-green-500/20 transition-all uppercase tracking-tighter">Send</button>
                            <button onClick={handleCopyKey} className="px-3 py-1 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 text-[10px] font-bold rounded border border-zinc-700 transition-all uppercase tracking-tighter">Copy</button>
                            <button onClick={handleClearKey} className="px-3 py-1 bg-red-600/10 hover:bg-red-600/20 text-red-500 text-[10px] font-bold rounded border border-red-500/20 transition-all uppercase tracking-tighter">Clear</button>
                        </div>
                    </div>
                    <textarea 
                        value={notepadKey}
                        onChange={(e) => setNotepadKey(e.target.value)}
                        className="w-full h-[48px] bg-black border border-zinc-800 rounded p-2 text-green-400 font-mono text-[11px] leading-[18px] resize-none focus:outline-none focus:border-green-500/30 whitespace-pre overflow-x-auto scrollbar-thin scrollbar-thumb-zinc-800"
                        placeholder="Enter API key here..."
                    />
                </div>
            </div>

            <main className="max-w-6xl mx-auto px-6 py-12 space-y-16">
                {error && (
                    <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm flex items-center gap-3">
                        <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        {error}
                    </div>
                )}

                {/* Video Generation */}
                <section className="bg-zinc-900 border border-zinc-800 rounded-3xl p-8 shadow-2xl">
                    <h2 className="text-2xl font-bold mb-2">AI Video Generation (Veo 3.1 Fast)</h2>
                    <div className="flex flex-col gap-4">
                        <textarea
