                            onChange={(e) => setGenPrompt(e.target.value)}
                            placeholder="Describe a cinematic scene..."
                            className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white focus:outline-none focus:ring-1 focus:ring-indigo-500/50 resize-none transition-all"
                        />
                        <div className="flex justify-end">
                            <button onClick={handleGenerateVideo} disabled={isGenerating || !genPrompt.trim()} className="px-8 py-3 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all flex items-center gap-2 disabled:opacity-50">
                                {isGenerating ? <SpinnerIcon /> : 'Generate Video'}
                            </button>
                        </div>
                    </div>
                </section>

                {/* Player & Frames */}
                <section className="grid lg:grid-cols-2 gap-12">
                    <div className="space-y-6">
                        <h3 className="text-xl font-bold">Local Player</h3>
                        <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-4">
                            {videoSrc ? (
                                <div className="space-y-4">
                                    <video 
                                        ref={videoRef} src={videoSrc} className="w-full rounded-2xl aspect-video bg-black"
                                        onLoadedMetadata={() => setDuration(videoRef.current?.duration || 0)}
                                        onTimeUpdate={() => setCurrentTime(videoRef.current?.currentTime || 0)}
                                    />
                                    <div className="flex items-center gap-4">
                                        <button onClick={() => { videoRef.current?.paused ? videoRef.current.play() : videoRef.current?.pause(); setIsPlaying(!videoRef.current?.paused); }} className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center">
                                            {isPlaying ? <PauseIcon /> : <PlayIcon />}
                                        </button>
                                        <input type="range" min={0} max={duration} step={0.1} value={currentTime} onChange={(e) => { if(videoRef.current) videoRef.current.currentTime = Number(e.target.value); }} className="flex-1 h-1.5 bg-zinc-800 rounded-full appearance-none accent-indigo-500" />
                                        <span className="text-[10px] font-mono text-zinc-500">{formatTime(currentTime)} / {formatTime(duration)}</span>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => {
                                            if (videoRef.current) {
                                                const canvas = document.createElement('canvas');
                                                canvas.width = videoRef.current.videoWidth;
                                                canvas.height = videoRef.current.videoHeight;
                                                canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
                                                setFrames(prev => [{
                                                    id: crypto.randomUUID(),
                                                    src: canvas.toDataURL('image/png'),
                                                    title: 'Captured Frame',
                                                    prompt: '',
                                                    originalFileName: `frame-${Date.now()}.png`,
                                                    selectedModel: 'gemini-2.5-flash-image'
                                                }, ...prev]);
                                            }
                                        }} className="flex-1 py-3 bg-zinc-800 hover:bg-zinc-700 rounded-xl text-xs font-bold transition-all">Capture Frame</button>
                                        <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-3 bg-zinc-950 border border-zinc-800 rounded-xl text-xs font-bold transition-all">Choose Video</button>
                                    </div>
                                </div>
                            ) : (
                                <div onClick={() => fileInputRef.current?.click()} className="aspect-video flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-2xl cursor-pointer p-8">
                                    <UploadIcon /><p className="font-bold text-zinc-400">Click to Upload MP4</p>
                                </div>
                            )}
                            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="video/mp4" className="hidden" />
                        </div>
                    </div>

                    <div className="space-y-6">
                        <h3 className="text-xl font-bold">Image Processing</h3>
                        <div className="space-y-4 max-h-[600px] overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-zinc-800">
                            {frames.map(f => (
