// --- MAIN APP COMPONENT ---
const App: React.FC = () => {
    const [notepadKey, setNotepadKey] = useState<string>('');
    const [activeApiKey, setActiveApiKey] = useState<string>('');
    const [selectedTextModel, setSelectedTextModel] = useState<string>('gemini-3-flash-preview');

    const [videoSrc, setVideoSrc] = useState<string | null>(null);
    const [error, setError] = useState<string>('');
    const [showQuotaHint, setShowQuotaHint] = useState<boolean>(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);
    const [videoFileName, setVideoFileName] = useState<string>('');
    const [frames, setFrames] = useState<Frame[]>([]);
    const [isProcessing, setIsProcessing] = useState<boolean>(false);

    const [isPlaying, setIsPlaying] = useState(true);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [volume, setVolume] = useState(1);
    const [isMuted, setIsMuted] = useState(false);

    useEffect(() => {
        const savedKey = localStorage.getItem('GEMINI_CUSTOM_API_KEY');
        const savedTextModel = localStorage.getItem('GEMINI_SELECTED_TEXT_MODEL');
        const initialKey = savedKey || process.env.API_KEY || '';

        setActiveApiKey(initialKey);
        setNotepadKey(initialKey || 'no API key');
        if (savedTextModel) setSelectedTextModel(savedTextModel);
    }, []);

    const handleSendKey = () => {
        const cleanKey = notepadKey.trim();
        if (cleanKey && cleanKey !== 'no API key') {
            localStorage.setItem('GEMINI_CUSTOM_API_KEY', cleanKey);
            setActiveApiKey(cleanKey);
            setError('');
            setShowQuotaHint(false);
        } else {
            setError('Please enter a valid API Key');
        }
    };

    const handleTextModelChange = (model: string) => {
        setSelectedTextModel(model);
        localStorage.setItem('GEMINI_SELECTED_TEXT_MODEL', model);
    };

    const handleFileChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        setError('');
        setShowQuotaHint(false);
        setFrames([]);
        if (videoSrc) URL.revokeObjectURL(videoSrc);
        if (file && file.type === 'video/mp4') {
            setVideoSrc(URL.createObjectURL(file));
            setVideoFileName(file.name);
        } else if (file) {
            setError('Invalid file type. Please select a .mp4 video file.');
        }
    }, [videoSrc]);

    const handleCaptureFrame = () => {
        if (!videoRef.current) return;
        const video = videoRef.current;
        const canvas = document.createElement('canvas');
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        canvas.getContext('2d')?.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/png');
        const name = videoFileName.split('.').slice(0, -1).join('.') || videoFileName;

        setFrames(prev => [{
            id: crypto.randomUUID(),
            src: dataUrl,
            title: 'Captured Frame',
            prompt: '',
            originalFileName: `${formatTimeForFilename(currentTime)}_${name}.png`
        }, ...prev]);
    };

    const handleImageProcessing = async (sourceFrameId: string, prompt: string, resultTitle: string, model: string) => {
        const frame = frames.find(f => f.id === sourceFrameId);
        const currentKey = activeApiKey || process.env.API_KEY;
        if (!frame || isProcessing || !currentKey || currentKey === 'no API key') return;

        setIsProcessing(true);
        setError('');
        setShowQuotaHint(false);
        try {
            const ai = new GoogleGenAI({ apiKey: currentKey });
            const response = await ai.models.generateContent({
                model: model, 
                contents: {
                    parts: [
                        { inlineData: { data: frame.src.split(',')[1], mimeType: 'image/png' } },
                        { text: prompt },
                    ],
                },
                config: { responseModalities: [Modality.IMAGE] },
            });

            const processedBase64 = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
            if (processedBase64) {
                setFrames(prev => [{
                    id: crypto.randomUUID(),
                    src: `data:image/png;base64,${processedBase64}`,
                    title: resultTitle,
                    prompt: '',
                    originalFileName: `edited_${frame.originalFileName}`
                }, ...prev]);
            } else {
                throw new Error(response.text || "No image data returned.");
            }
        } catch (err: any) {
            handleError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleTextProcessing = async (frameId: string, action: 'describe' | 'polish' | 'translate' | 'caption') => {
        const frame = frames.find(f => f.id === frameId);
        const currentKey = activeApiKey || process.env.API_KEY;
        if (!frame || isProcessing || !currentKey) return;

        setIsProcessing(true);
        setError('');
        try {
            const ai = new GoogleGenAI({ apiKey: currentKey });
            let prompt = "";
            switch (action) {
                case 'describe': prompt = "Describe this image in detail and suggest a creative prompt to modify it."; break;
                case 'polish': prompt = `Look at the user's current prompt: "${frame.prompt}". Polish and improve this prompt to get better visual results when editing this specific image. Return only the improved prompt text.`; break;
                case 'translate': prompt = "Translate the current prompt (if any) or describe this image concisely in both Thai and English. If there is a prompt, provide a high-quality translation of it."; break;
                case 'caption': prompt = "Write 5 short, engaging social media captions for this image with hashtags."; break;
            }

            const response = await ai.models.generateContent({
                model: selectedTextModel,
                contents: {
                    parts: [
                        { inlineData: { data: frame.src.split(',')[1], mimeType: 'image/png' } },
                        { text: prompt },
                    ],
                },
            });

            const text = response.text;
            if (text) {
                setFrames(prev => prev.map(f => f.id === frameId ? { ...f, textOutput: text } : f));
                if (action === 'polish') {
                    setFrames(prev => prev.map(f => f.id === frameId ? { ...f, prompt: text.trim() } : f));
                }
            }
        } catch (err: any) {
            handleError(err);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleError = (err: any) => {
        console.error("API Error:", err);
        const msg = err.message || "";
        if (msg.includes("429") || msg.toLowerCase().includes("quota")) {
            setError("Quota Exceeded (429): Limit reached for this key.");
            setShowQuotaHint(true);
        } else if (msg.includes("requested entity was not found")) {
            setError("API Key Error. Please re-select key.");
            window.aistudio?.openSelectKey();
        } else {
            setError(`Error: ${msg || 'Unknown error occurred.'}`);
        }
    };

    return (
        <div className="bg-gray-900 min-h-screen flex flex-col items-center justify-start font-sans text-white pb-20">
            {/* ENHANCED NOTEPAD BAR */}
            <div className="w-full bg-zinc-950 border-b border-zinc-800 p-3 shadow-xl sticky top-0 z-50">
                <div className="max-w-6xl mx-auto flex flex-col gap-3">
                    <div className="flex items-center justify-between px-1">
                        <div className="flex items-center gap-4">
                            <label className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                                <span className={`w-2 h-2 rounded-full ${activeApiKey ? 'bg-green-500' : 'bg-red-500'} animate-pulse`}></span>
                                API Key :
                            </label>
                            {/* NEW TEXT REASONING MODEL DROPDOWN */}
                            <div className="flex items-center gap-2 border-l border-zinc-800 pl-4">
                                <label className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Text Model:</label>
                                <select 
                                    value={selectedTextModel}
                                    onChange={(e) => handleTextModelChange(e.target.value)}
                                    className="bg-black border border-zinc-800 rounded px-2 py-0.5 text-[10px] text-zinc-400 focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all font-bold uppercase"
                                >
                                    <optgroup label="Latest Models" className="bg-zinc-900">
                                        <option value="gemini-flash-latest">Gemini Flash Latest</option>
                                        <option value="gemini-flash-lite-latest">Gemini Lite Latest</option>
                                    </optgroup>
                                    <optgroup label="Reasoning Models" className="bg-zinc-900">
                                        <option value="gemini-3-flash-preview">Gemini 3 Flash (Fast)</option>
                                        <option value="gemini-3-pro-preview">Gemini 3 Pro (Smart)</option>
                                    </optgroup>
                                </select>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <button onClick={handleSendKey} className="px-3 py-1 bg-green-600/10 hover:bg-green-600/20 text-green-500 text-[10px] font-black rounded border border-green-500/20 transition-all uppercase">Send</button>
                            <button onClick={() => setNotepadKey('')} className="px-3 py-1 bg-red-600/10 hover:bg-red-600/20 text-red-500 text-[10px] font-bold rounded border border-red-500/20 transition-all uppercase">Clear</button>
                        </div>
                    </div>
                    <textarea 
                        value={notepadKey}
                        onChange={(e) => setNotepadKey(e.target.value)}
                        className="w-full h-10 bg-black border border-zinc-800 rounded p-2 text-green-400 font-mono text-xs resize-none focus:outline-none focus:border-green-500/30 whitespace-pre overflow-x-auto"
                        placeholder="Paste Gemini API key here..."
                    />
                </div>
            </div>

            <header className="w-full max-w-[500px] text-center my-8">
                <h1 className="text-4xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-cyan-400 via-indigo-400 to-purple-500">
                    FRAME CAPTURE AI
                </h1>
                <p className="text-xs text-zinc-500 uppercase tracking-[0.2em] font-bold mt-2 opacity-80">
                    Process & Edit Video Frames with Gemini
                </p>
            </header>

            <main className="bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl p-4 w-full max-w-[500px] box-content">
                <div className="w-[500px] h-auto flex items-center justify-center">
                    {videoSrc ? (
                        <VideoPlayer 
                            src={videoSrc} videoRef={videoRef} isPlaying={isPlaying} currentTime={currentTime}
                            duration={duration} volume={volume} isMuted={isMuted} togglePlayPause={() => {
                                if (videoRef.current?.paused) videoRef.current.play(); else videoRef.current?.pause();
                                setIsPlaying(!videoRef.current?.paused);
                            }}
                            handleSeek={(e) => { if(videoRef.current) videoRef.current.currentTime = Number(e.target.value); }}
                            handleVolumeChange={(e) => { 
                                const v = Number(e.target.value); setVolume(v); 
                                if(videoRef.current) { videoRef.current.volume = v; setIsMuted(v === 0); }
                            }} 
                            toggleMute={() => { setIsMuted(!isMuted); if(videoRef.current) videoRef.current.muted = !isMuted; }}
                            onPlay={() => setIsPlaying(true)} onPause={() => setIsPlaying(false)}
                            onTimeUpdate={() => setCurrentTime(videoRef.current?.currentTime || 0)} 
                            onLoadedMetadata={() => setDuration(videoRef.current?.duration || 0)}
                            onEnded={() => setIsPlaying(false)} 
                            onSkipToEnd={() => { if(videoRef.current) videoRef.current.currentTime = videoRef.current.duration; }}
                        />
                    ) : (
                        <UploadPlaceholder onClick={() => fileInputRef.current?.click()} />
                    )}
                </div>
            </main>

            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".mp4" className="hidden" />

            {error && (
                 <div className="mt-4 bg-red-900/30 border border-red-500/50 text-red-300 px-4 py-4 rounded-xl text-xs max-w-[500px] w-full text-center flex flex-col gap-2">
                    <span className="font-bold uppercase tracking-widest">{error}</span>
                    {showQuotaHint && (
                        <div className="flex gap-4 justify-center mt-1">
                            <button onClick={() => window.aistudio?.openSelectKey()} className="text-[10px] bg-white/10 hover:bg-white/20 px-3 py-1 rounded-full uppercase font-black">Re-select Key</button>
                            <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[10px] bg-indigo-500/20 hover:bg-indigo-500/30 px-3 py-1 rounded-full uppercase font-black">Billing Info</a>
                        </div>
                    )}
                </div>
            )}

            {videoSrc && (
                <div className="flex items-center justify-center gap-4 mt-6">
                    <button onClick={() => fileInputRef.current?.click()} className="bg-zinc-800 hover:bg-zinc-700 text-white font-bold py-3 px-6 rounded-xl transition-all text-[10px] uppercase tracking-widest border border-zinc-700">Change Video</button>
                    <button onClick={handleCaptureFrame} className="bg-cyan-600 hover:bg-cyan-500 text-white font-bold py-3 px-8 rounded-xl transition-all transform hover:scale-105 shadow-lg shadow-cyan-900/20 text-[10px] uppercase tracking-widest">Capture Frame</button>
                </div>
            )}

            <div className="w-full flex flex-col items-center pb-8 px-4">
                 {frames.map(frame => (
                    <ImageFrame
                        key={frame.id}
                        frame={frame}
                        onUpdatePrompt={(id, p) => setFrames(prev => prev.map(f => f.id === id ? { ...f, prompt: p } : f))}
                        onDelete={(id) => setFrames(prev => prev.filter(f => f.id !== id))}
                        onSave={async (id) => {
                            const f = frames.find(x => x.id === id);
                            if (!f) return;
                            const blob = await dataURLToBlob(f.src);
                            const link = document.createElement('a');
                            link.href = URL.createObjectURL(blob);
                            link.download = f.originalFileName;
                            link.click();
                        }}
                        onProcessImage={handleImageProcessing}
                        onProcessText={handleTextProcessing}
                        onOpenFile={(id, file) => {
                            const reader = new FileReader();
                            reader.onload = (e) => setFrames(prev => prev.map(f => f.id === id ? { ...f, src: e.target?.result as string, originalFileName: file.name } : f));
                            reader.readAsDataURL(file);
                        }}
                        isProcessing={isProcessing}
                    />
                 ))}
            </div>
        </div>
    );
};

export default App;

