import React, { useState, useEffect } from 'react';
import { VideoAspectRatio, VideoResolution, GeneratedVideo } from './types';
import { generateVideo } from './services/geminiService';
import ApiKeyManager from './components/ApiKeyManager';
import VideoGrid from './components/VideoGrid';

/**
 * Main App component for the Veo Video Generation Studio.
 * Handles the orchestration of video generation, state management for creations,
 * and ensures compliance with Gemini API key selection protocols.
 */
const App: React.FC = () => {
  const [videos, setVideos] = useState<GeneratedVideo[]>([]);
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [aspectRatio, setAspectRatio] = useState<VideoAspectRatio>(VideoAspectRatio.LANDSCAPE);
  const [resolution, setResolution] = useState<VideoResolution>(VideoResolution.P1080);
  const [isKeyValidated, setIsKeyValidated] = useState(false);

  // Load previously generated videos from local storage on component mount
  useEffect(() => {
    const saved = localStorage.getItem('veo_creations_history');
    if (saved) {
      try {
        setVideos(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to restore video history:", e);
      }
    }
  }, []);

  // Sync video creations to local storage whenever the list changes
  useEffect(() => {
    localStorage.setItem('veo_creations_history', JSON.stringify(videos));
  }, [videos]);

  /**
   * Triggers the Veo video generation process.
   * Handles polling, error states, and session validation.
   */
  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || isGenerating) return;

    setIsGenerating(true);
    setError(null);

    try {
      // Calls the geminiService which handles the complex Veo operation polling
      const url = await generateVideo(prompt, aspectRatio, resolution);

      const newVideo: GeneratedVideo = {
        id: crypto.randomUUID(),
        url,
        prompt,
        timestamp: Date.now(),
        status: 'completed'
      };

      setVideos(prev => [newVideo, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error("Video Generation Error:", err);
      setError(err.message || 'An unexpected error occurred during the generation process.');

      // If the API key is revoked or the project is not found, force re-selection
      if (err.message === "Requested entity was not found." || err.message === "API_KEY_INVALID") {
        setIsKeyValidated(false);
      }
    } finally {
      setIsGenerating(false);
    }
  };

  /**
   * Helper to re-open the API key selection dialog.
   */
  const handleSwitchKey = async () => {
    try {
      await window.aistudio.openSelectKey();
      setIsKeyValidated(true);
    } catch (err) {
      console.error("Failed to open key selection:", err);
    }
  };

  // Mandatory check: Veo generation requires explicit user API key selection
  if (!isKeyValidated) {
    return <ApiKeyManager onKeyValidated={() => setIsKeyValidated(true)} />;
  }

  return (
    <div className="min-h-screen bg-zinc-950 text-zinc-100 font-sans selection:bg-indigo-500/30">
      {/* Top Navigation Bar */}
      <nav className="border-b border-zinc-800 bg-zinc-950/50 backdrop-blur-xl sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/30">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            </div>
            <h1 className="text-xl font-bold tracking-tight">Veo<span className="text-indigo-400">Studio</span></h1>
          </div>
          <button 
            onClick={handleSwitchKey}
            className="text-xs font-bold text-zinc-400 hover:text-white transition-all bg-zinc-900 px-4 py-2 rounded-xl border border-zinc-800 hover:border-zinc-700 active:scale-95"
          >
            Change API Key
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 py-12">
        {/* Creation Workshop Section */}
        <section className="mb-24">
          <div className="max-w-3xl mx-auto">
            <header className="text-center mb-10">
              <h2 className="text-4xl sm:text-5xl font-extrabold mb-4 bg-gradient-to-br from-white via-zinc-200 to-zinc-500 bg-clip-text text-transparent">
                Create with Veo
              </h2>
              <p className="text-zinc-400 text-lg max-w-xl mx-auto">
                Transform your most ambitious ideas into high-definition cinematic reality.
              </p>
            </header>

            <form onSubmit={handleGenerate} className="space-y-6">
              <div className="relative group">
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Describe your scene: 'An epic wide shot of an astronaut surfing on cosmic waves made of stardust, high contrast, 8k resolution...'"
                  className="w-full h-48 bg-zinc-900/50 border-2 border-zinc-800 rounded-[2rem] p-8 text-lg text-white placeholder-zinc-600 focus:outline-none focus:border-indigo-500/50 transition-all resize-none group-hover:bg-zinc-900 group-hover:border-zinc-700"
                  disabled={isGenerating}
                />

                {/* Configuration Controls */}
                <div className="absolute bottom-6 right-6 flex items-center gap-3">
                  <div className="flex flex-col gap-1">
                    <label className="text-[10px] font-bold text-zinc-500 uppercase px-1">Ratio</label>
                    <select 
                      value={aspectRatio}
                      onChange={(e) => setAspectRatio(e.target.value as VideoAspectRatio)}
                      className="bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-1.5 text-xs font-bold text-zinc-300 focus:outline-none hover:bg-zinc-700 transition-colors cursor-pointer"
                      disabled={isGenerating}
                    >
                      <option value={VideoAspectRatio.LANDSCAPE}>16:9 Landscape</option>
                      <option value={VideoAspectRatio.PORTRAIT}>9:16 Portrait</option>
                    </select>
                  </div>
                  <div className="flex flex-col gap-1">
                    <label className="text-[10px] font-bold text-zinc-500 uppercase px-1">Quality</label>
                    <select 
                      value={resolution}
                      onChange={(e) => setResolution(e.target.value as VideoResolution)}
                      className="bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-1.5 text-xs font-bold text-zinc-300 focus:outline-none hover:bg-zinc-700 transition-colors cursor-pointer"
                      disabled={isGenerating}
                    >
                      <option value={VideoResolution.P720}>720p</option>
                      <option value={VideoResolution.P1080}>1080p</option>
                    </select>
                  </div>
                </div>
              </div>

              {/* Error Feedback */}
              {error && (
                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm flex items-start gap-3 animate-in fade-in slide-in-from-top-2">
                  <svg className="w-5 h-5 mt-0.5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  <p className="leading-tight">{error}</p>
                </div>
              )}

              {/* Action Button */}
              <button
                type="submit"
                disabled={isGenerating || !prompt.trim()}
                className={`w-full py-6 rounded-[2rem] font-bold text-xl transition-all flex items-center justify-center gap-4 ${
                  isGenerating 
                  ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed border border-zinc-700' 
                  : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-2xl shadow-indigo-500/20 active:scale-[0.97]'
                }`}
              >
                {isGenerating ? (
                  <>
                    <svg className="animate-spin h-6 w-6" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                    </svg>
                    <span>Generating Creation...</span>
                  </>
                ) : (
                  <>
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                    <span>Generate Video</span>
                  </>
                )}
              </button>

              {/* Progress UI */}
              {isGenerating && (
                <div className="text-center animate-pulse">
                   <p className="text-sm text-indigo-400 font-bold uppercase tracking-[0.2em] mb-1">Processing on Google Veo Engine</p>
                   <p className="text-xs text-zinc-500">This typically takes 2-3 minutes. Please stay on this page.</p>
                </div>
              )}
            </form>
          </div>
        </section>

        {/* Portfolio Gallery Section */}
        <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="flex items-center justify-between mb-10 border-b border-zinc-900 pb-5">
            <h3 className="text-2xl font-bold">Your Portfolio</h3>
            <span className="text-[10px] font-black text-zinc-500 bg-zinc-900 px-3 py-1.5 rounded-full uppercase tracking-widest border border-zinc-800">
              {videos.length} Creations
            </span>
          </div>

          <VideoGrid 
            videos={videos} 
            onPlay={(video) => window.open(video.url, '_blank')}
          />
        </section>
      </main>

      {/* Footer Branding */}
      <footer className="max-w-7xl mx-auto px-4 py-16 border-t border-zinc-900/50 mt-32 text-center opacity-40 hover:opacity-100 transition-opacity">
        <p className="text-zinc-600 text-sm font-medium tracking-wide flex items-center justify-center gap-2">
          Powered by Gemini Veo 3.1 & Google Cloud
        </p>
      </footer>
    </div>
  );
};

// Fix: Add missing default export
export default App;

